from dataclasses import dataclass, field
from datetime import date
from enum import Enum

class OperationalSignalType(str, Enum):
    LATENCY_SPIKE        = "latency_spike"
    ERROR_RATE_INCREASE  = "error_rate_increase"
    COST_ANOMALY         = "cost_anomaly"
    TOKEN_USAGE_DRIFT    = "token_usage_drift"     # responses getting longer or shorter
    ALERT_FATIGUE        = "alert_fatigue"         # too many low-signal alerts
    RUNBOOK_GAP          = "runbook_gap"           # incident required action not in runbook
    MODEL_BEHAVIOR_DRIFT = "model_behavior_drift"  # response patterns changed without code change

@dataclass
class SREFeedbackRecord:
    signal_type: OperationalSignalType
    observed_date: date
    duration_days: int         # how long the pattern was observed before reporting
    affected_endpoints: list[str]
    description: str
    incident_ids: list[str] = field(default_factory=list)
    recommended_action: str = ""
    severity: str = "low"      # "low" | "medium" | "high" | "critical"
    owner: str = ""

    def backlog_priority(self) -> int:
        """
        Maps severity and signal type to backlog priority (1=highest, 5=lowest).
        """
        severity_map = {"critical": 1, "high": 2, "medium": 3, "low": 4}
        base = severity_map.get(self.severity, 5)
        if self.signal_type in (
            OperationalSignalType.MODEL_BEHAVIOR_DRIFT,
            OperationalSignalType.ERROR_RATE_INCREASE,
        ):
            return max(1, base - 1)
        return base

    def has_incident_evidence(self) -> bool:
        return len(self.incident_ids) > 0

@dataclass
class SREFeedbackLog:
    service_name: str
    records: list[SREFeedbackRecord] = field(default_factory=list)

    def by_signal_type(self, signal_type: OperationalSignalType) -> list[SREFeedbackRecord]:
        return [r for r in self.records if r.signal_type == signal_type]

    def high_priority(self) -> list[SREFeedbackRecord]:
        return [r for r in self.records if r.backlog_priority() <= 2]

    def model_behavior_signals(self) -> list[SREFeedbackRecord]:
        return self.by_signal_type(OperationalSignalType.MODEL_BEHAVIOR_DRIFT)

from dataclasses import dataclass, field
from datetime import date

@dataclass
class SupportTicketSummary:
    ticket_id: str
    submitted_date: date
    category: str               # from support team's taxonomy
    subcategory: str
    customer_tier: str          # "enterprise" | "team" | "individual"
    model_id: str | None        # if the customer reported which model
    description: str
    resolved: bool
    resolution_notes: str = ""
    escalated_to_product: bool = False
    anthropic_support_opened: bool = False

@dataclass
class SupportTicketCluster:
    cluster_id: str
    theme: str                   # human-readable description of the cluster
    tickets: list[SupportTicketSummary] = field(default_factory=list)
    date_range_start: date = None
    date_range_end: date = None
    estimated_affected_users: int = 0
    backlog_item_created: bool = False
    product_team_owner: str = ""

    def is_enterprise_impacting(self) -> bool:
        return any(t.customer_tier == "enterprise" for t in self.tickets)

    def volume(self) -> int:
        return len(self.tickets)

    def priority_label(self) -> str:
        if self.is_enterprise_impacting():
            return "HIGH: enterprise-impacting cluster"
        if self.volume() >= 10:
            return "MEDIUM: high-volume cluster"
        return "LOW: emerging cluster"

    def requires_anthropic_escalation(self) -> bool:
        return any(t.anthropic_support_opened for t in self.tickets)

from dataclasses import dataclass, field
from datetime import date

@dataclass
class WeeklyReviewAgendaItem:
    source: str               # "sre" | "support" | "analytics"
    item_count: int
    top_signals: list[str]   # 3–5 most significant signals this week
    new_backlog_items: int
    escalations: list[str] = field(default_factory=list)

@dataclass
class WeeklyOperatorReview:
    review_date: date
    attendees: list[str]
    agenda_items: list[WeeklyReviewAgendaItem] = field(default_factory=list)
    decisions: list[str] = field(default_factory=list)
    action_items: list[str] = field(default_factory=list)
    next_review_date: date = None

    def total_signals_reviewed(self) -> int:
        return sum(a.item_count for a in self.agenda_items)

    def any_escalations(self) -> bool:
        return any(a.escalations for a in self.agenda_items)

    def meeting_health(self) -> str:
        if not self.action_items:
            return "WARNING: no action items produced — review may not have been substantive"
        if len(self.action_items) > 10:
            return "WARNING: too many action items — consider prioritisation or delegation"
        if self.any_escalations() and "escalation" not in " ".join(self.decisions).lower():
            return "WARNING: escalations present but not addressed in decisions"
        return "HEALTHY"
